#!/usr/bin/env bash
## INSTALADOR DE MODEL2EMU (SEGA MODEL 2)
## FECHA DE CREACIÓN: 23 de mayo de 2026
## FECHAS DE MODIFICACIÓN: Configurado para entorno Wine personalizado

## VARIABLES
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" >/dev/null 2>&1 && pwd -P)"
ROOTDIR="$(realpath "$SCRIPT_DIR/..")"

DOWNLOAD_URL="https://github.com/batocera-linux/model2emu/raw/refs/heads/main/m2emulator.zip"
INSTALL_DIR="/opt/model2emu"
EMU_DIR="$INSTALL_DIR/drive_c/model2emu"
BIN_LINK="/usr/local/bin/model2emu"
DESKTOP_FILE="/usr/local/share/applications/model2emu.desktop"
ICON_PATH="/usr/share/icons/hicolor/scalable/apps/model2emu.svg"

# Detectar el usuario y grupo real tras el comando sudo
REAL_USER="${SUDO_USER:-$(id -nu 1000)}"
REAL_GROUP="$(id -ng "$REAL_USER")"

## FUNCIONES

function error(){
    echo "[ERROR] $@. F"
    exit 1
}

function check_root(){
    if [ $(id -u) -ne 0 ]; then
        echo "[ERROR] Se necesitan permisos de root."
        exit 1
    fi
}

function check_dependencies(){
    if ! command -v wine >/dev/null 2>&1; then
        error "Wine no está instalado en el sistema. Instálalo antes de continuar"
    fi
    if ! command -v unzip >/dev/null 2>&1; then
        error "La herramienta 'unzip' no está instalada. Instálala antes de continuar"
    fi
}

function svg_icon(){
    # Genera un logo en formato SVG geométrico inspirado en Sega y el clásico número 2
    mkdir -p "$(dirname "$ICON_PATH")"
