function install_wine_version(){
    echo "[INFO] Verificando dependencias del sistema..."
    check_dependencies

    echo "[INFO] Creando directorio e inicializando WINEPREFIX para el usuario $REAL_USER..."
    mkdir -p "$INSTALL_DIR"
    chown "$REAL_USER:$REAL_GROUP" "$INSTALL_DIR"

    # Inicializar el prefix de Wine de manera silenciosa usando la identidad del usuario real
    sudo -u "$REAL_USER" WINEPREFIX="$INSTALL_DIR" wineboot --init >/dev/null 2>&1

    echo "[INFO] Creando el directorio del emulador..."
    mkdir -p "$EMU_DIR"
    chown "$REAL_USER:$REAL_GROUP" "$EMU_DIR"

    echo "[INFO] Descargando m2emulator.zip desde el repositorio de Batocera..."
    TMP_ZIP=$(mktemp /tmp/m2emu_XXXXXX.zip)
    curl -L "$DOWNLOAD_URL" -o "$TMP_ZIP"

    if [ $? -ne 0 ]; then
        rm -f "$TMP_ZIP"
        error "Error durante la descarga del archivo zip"
    fi

    echo "[INFO] Extrayendo archivos en la ruta de destino..."
    unzip -o "$TMP_ZIP" -d "$EMU_DIR" >/dev/null
    rm -f "$TMP_ZIP"

    # Asegurar que toda la estructura mantenga los permisos correctos del usuario
    chown -R "$REAL_USER:$REAL_GROUP" "$INSTALL_DIR"

    echo "[INFO] Configurando script de lanzamiento binario..."
    cat <<EOF > "$BIN_LINK"
#!/usr/bin/env bash
export WINEPREFIX="$INSTALL_DIR"
cd "$EMU_DIR"

# El zip suele contener Emulator.exe o EmulatorMultiCPU.exe
EXE_FILE="Emulator.exe"
if [ ! -f "\$EXE_FILE" ] && [ -f "EmulatorMultiCPU.exe" ]; then
    EXE_FILE="EmulatorMultiCPU.exe"
fi

exec wine "\$EXE_FILE" "\$@"
EOF
    chmod +x "$BIN_LINK"

    svg_icon

    # Crear acceso directo para el menú de aplicaciones del sistema
    mkdir -p "$(dirname "$DESKTOP_FILE")"
    cat <<EOF > "$DESKTOP_FILE"
[Desktop Entry]
Categories=Game;Emulator;
Comment=Sega Model 2 Emulator via Wine
Exec=$BIN_LINK
GenericName=Sega Model 2 Emulator
Icon=$ICON_PATH
Name=Model2Emu
StartupNotify=true
Terminal=false
Type=Application
Version=1.0
EOF

    echo "[INFO] Instalación de Model2Emu completada con éxito."
}

function uninstall_app(){
    echo "[INFO] Buscando instalaciones de Model2Emu..."
    local found=0

    # Comprobar y eliminar estructura Wine/Archivos
    if [ -d "$INSTALL_DIR" ] || [ -f "$BIN_LINK" ]; then
        echo "[INFO] Eliminando WINEPREFIX y archivos de /opt..."
        rm -f "$BIN_LINK"
        rm -rf "$INSTALL_DIR"
        rm -f "$DESKTOP_FILE"
        rm -f "${ICON_PATH}"
        found=1
    fi

    if [ $found -eq 0 ]; then
        echo "[INFO] No se encontró ninguna instalación de Model2Emu."
    else
        echo "[INFO] Desinstalación completada."
    fi
}

## LLAMADAS

check_root

if [ -z "$1" ]; then
    echo "Uso: $0 [-i | -u]"
    echo "  -i : Instalar configurando WINEPREFIX propio en /opt y descargando archivos"
    echo "  -u : Desinstalar por completo (elimina archivos, WINEPREFIX, binario y acceso directo)"
    exit 1
fi

echo "[INFO] Ejecutando acción para el parámetro: $1"

case $1 in
    "-i") install_wine_version;;
    "-u") uninstall_app;;
    *)
        echo "[ERROR] Parámetro no reconocido."
        exit 1
        ;;
esac

exit 0
